1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type Damage = { itemType: string; amount: number };
9	export type Incident = { cause: string; damages: Damage[] };
10	export type QuoteStep = { op: "quote"; items: Item[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	export type QuoteResult = { premium: number };
15	export type ClaimResult = { payout: number; remainingCap: number };
16	export type ScenarioResult = { results: (QuoteResult | ClaimResult)[] };
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	// Rounding policies — both round in MHPCO's favor
22	const roundPremiumInMHPCOFavor = Math.ceil;
23	const roundPayoutInMHPCOFavor = Math.floor;
24	
25	const BASE_PREMIUMS: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	  rune: 25,
31	  moonstone: 25,
32	};
33	
34	const baseFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
35	
36	const BLOCK_OF_3_PREMIUM = 60;
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
40	
41	const componentBlockBase = (count: number, type: string): number =>
42	  count === 3 ? BLOCK_OF_3_PREMIUM : count * baseFor({ type });
43	
44	const componentsBase = (components: Item[]): number => {
45	  const countsByType = components.reduce<Record<string, number>>((counts, item) => {
46	    counts[item.type] = (counts[item.type] ?? 0) + 1;
47	    return counts;
48	  }, {});
49	  return Object.entries(countsByType).reduce(
50	    (sum, [type, count]) => sum + componentBlockBase(count, type),
51	    0,
52	  );
53	};
54	
55	const sumBasePremiums = (items: Item[]): number => {
56	  const components = items.filter(isComponent);
57	  const standaloneBase = items
58	    .filter((item) => !isComponent(item))
59	    .reduce((sum, item) => sum + baseFor(item), 0);
60	  return componentsBase(components) + standaloneBase;
61	};
62	
63	const CURSE_RATE = 0.5;
64	const HIGH_ENCHANTMENT_RATE = 0.3;
65	const HIGH_ENCHANTMENT_THRESHOLD = 5;
66	
67	const isCursed = (item: Item): boolean => item.cursed === true;
68	const hasHighEnchantment = (item: Item): boolean =>
69	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
70	
71	const surchargeFor = (item: Item): number => {
72	  const base = baseFor(item);
73	  const curse = isCursed(item) ? base * CURSE_RATE : 0;
74	  const highEnch = hasHighEnchantment(item) ? base * HIGH_ENCHANTMENT_RATE : 0;
75	  return curse + highEnch;
76	};
77	
78	const itemSurcharges = (items: Item[]): number =>
79	  items.reduce((sum, item) => sum + surchargeFor(item), 0);
80	
81	const LOYALTY_RATE = 0.2;
82	const LOYALTY_THRESHOLD_YEARS = 2;
83	const FOLLOWUP_CONTRACT_RATE = 0.15;
84	
85	const isLoyal = (customer: Customer): boolean =>
86	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
87	
88	const loyaltyDiscount = (itemsBase: number, customer: Customer): number =>
89	  isLoyal(customer) ? itemsBase * LOYALTY_RATE : 0;
90	
91	const followupDiscount = (itemsBase: number, quoteIndex: number): number =>
92	  quoteIndex > 0 ? itemsBase * FOLLOWUP_CONTRACT_RATE : 0;
93	
94	const totalDiscounts = (itemsBase: number, customer: Customer, quoteIndex: number): number =>
95	  loyaltyDiscount(itemsBase, customer) + followupDiscount(itemsBase, quoteIndex);
96	
97	const quotePremium = (items: Item[], customer: Customer, quoteIndex: number): number => {
98	  const itemsBase = sumBasePremiums(items);
99	  const surcharges = itemSurcharges(items);
100	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
101	  const discounts = totalDiscounts(itemsBase, customer, quoteIndex);
102	  return roundPremiumInMHPCOFavor(itemsBase + surcharges + firstInsurance - discounts + PROCESSING_FEE);
103	};
104	
105	const INSURANCE_VALUES: Record<string, number> = {
106	  sword: 1000,
107	  amulet: 600,
108	  staff: 800,
109	  potion: 400,
110	  rune: 250,
111	  moonstone: 250,
112	};
113	
114	const insuranceValueFor = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
115	
116	const insuranceSum = (items: Item[]): number =>
117	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
118	
119	const DEDUCTIBLE = 100;
120	const CAP_MULTIPLIER = 2;
121	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
122	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
123	
124	const qualifiesForHighEnchantmentClause = (item: Item): boolean =>
125	  (item.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
126	
127	const reimbursableAmount = (item: Item, damageAmount: number): number =>
128	  qualifiesForHighEnchantmentClause(item)
129	    ? damageAmount * CLAIM_HIGH_ENCHANTMENT_RATE
130	    : damageAmount;
131	
132	const payoutForDamage = (item: Item, damageAmount: number): number =>
133	  reimbursableAmount(item, damageAmount) - DEDUCTIBLE;
134	
135	const findPolicyItem = (items: Item[], itemType: string): Item =>
136	  items.find((item) => item.type === itemType) as Item;
137	
138	const totalPayout = (damages: Damage[], policyItems: Item[]): number =>
139	  damages.reduce(
140	    (sum, damage) => sum + payoutForDamage(findPolicyItem(policyItems, damage.itemType), damage.amount),
141	    0,
142	  );
143	
144	const claimResult = (incident: Incident, policyItems: Item[], availableCap: number): ClaimResult => {
145	  const desiredPayout = roundPayoutInMHPCOFavor(totalPayout(incident.damages, policyItems));
146	  const payout = Math.min(desiredPayout, availableCap);
147	  return { payout, remainingCap: availableCap - payout };
148	};
149	
150	export const runScenario = (scenario: Scenario): ScenarioResult => {
151	  const policies: Item[][] = [];
152	  const remainingCaps: number[] = [];
153	  const results = scenario.steps.map((step) => {
154	    if (step.op === "quote") {
155	      const premium = quotePremium(step.items, scenario.customer, policies.length);
156	      policies.push(step.items);
157	      remainingCaps.push(insuranceSum(step.items) * CAP_MULTIPLIER);
158	      return { premium };
159	    }
160	    const result = claimResult(step.incident, policies[step.policy], remainingCaps[step.policy]);
161	    remainingCaps[step.policy] = result.remainingCap;
162	    return result;
163	  });
164	  return { results };
165	};
